#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr int32_t IN_TILE = 2048;  // tile size for in_features loop

class KernelGemmBiasAddHardtanhMishGroupNormCustom {
public:
    __aicore__ inline KernelGemmBiasAddHardtanhMishGroupNormCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR weight, GM_ADDR lin_bias,
                                GM_ADDR bias, GM_ADDR gn_gamma, GM_ADDR gn_beta,
                                GM_ADDR y,
                                uint32_t batchSize, uint32_t inFeatures,
                                uint32_t outFeatures, uint32_t numGroups,
                                float eps, uint32_t tileLen)
    {
        batchSize_ = batchSize;
        inFeatures_ = inFeatures;
        outFeatures_ = outFeatures;
        numGroups_ = numGroups;
        eps_ = eps;
        tileLen_ = tileLen;

        xGm_.SetGlobalBuffer((__gm__ float*)x, batchSize * inFeatures);
        wGm_.SetGlobalBuffer((__gm__ float*)weight, outFeatures * inFeatures);
        linBiasGm_.SetGlobalBuffer((__gm__ float*)lin_bias, outFeatures);
        biasGm_.SetGlobalBuffer((__gm__ float*)bias, outFeatures);
        gnGammaGm_.SetGlobalBuffer((__gm__ float*)gn_gamma, outFeatures);
        gnBetaGm_.SetGlobalBuffer((__gm__ float*)gn_beta, outFeatures);
        yGm_.SetGlobalBuffer((__gm__ float*)y, batchSize * outFeatures);

        // UB buffers for entire output tile (outFeatures)
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue3_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue4_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue5_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue6_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (batchSize_ == 0 || inFeatures_ == 0 || outFeatures_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        if (blockIdx >= batchSize_) return;
        uint32_t sampleIdx = blockIdx;

        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        const uint32_t n = outFeatures_;

        // Step 1: Linear(x, weight, lin_bias) and add bias
        for (uint32_t i = 0; i < n; i++) {
            float sum = linBiasGm_.GetValue(i) + biasGm_.GetValue(i);
            uint32_t baseW = i * inFeatures_;
            AscendC::LocalTensor<float> sumTensor = tmpQueue6_.AllocTensor<float>();
            // Initialize sumTensor to 0
            sumTensor.SetValue(0, 0.0f);
            for (uint32_t j = 0; j < inFeatures_; j += IN_TILE) {
                uint32_t len = (j + IN_TILE <= inFeatures_) ? IN_TILE : (inFeatures_ - j);
                AscendC::LocalTensor<float> xTile = inQueueX_.AllocTensor<float>();
                AscendC::LocalTensor<float> wTile = tmpQueue1_.AllocTensor<float>();
                AscendC::DataCopy(xTile, xGm_[sampleIdx * inFeatures_ + j], len);
                AscendC::DataCopy(wTile, wGm_[baseW + j], len);
                AscendC::LocalTensor<float> prod = tmpQueue2_.AllocTensor<float>();
                AscendC::Mul(prod, xTile, wTile, len);
                AscendC::LocalTensor<float> partialSum = tmpQueue3_.AllocTensor<float>();
                // ReduceSum returns scalar tensor with 1 element
                AscendC::ReduceSum(partialSum, prod, len, 0);
                // Accumulate partial sum into sumTensor
                AscendC::Adds(sumTensor, partialSum, sumTensor.GetValue(0), 1);
                inQueueX_.FreeTensor(xTile);
                tmpQueue1_.FreeTensor(wTile);
                tmpQueue2_.FreeTensor(prod);
                tmpQueue3_.FreeTensor(partialSum);
            }
            sum += sumTensor.GetValue(0);
            tmpQueue6_.FreeTensor(sumTensor);
            yLocal.SetValue(i, sum);
        }

        // Step 2: Hardtanh (clamp to [-1, 1]) using vector Maximum/Minimum
        AscendC::LocalTensor<float> clampMax = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> clampMin = tmpQueue2_.AllocTensor<float>();
        AscendC::LocalTensor<float> t = tmpQueue3_.AllocTensor<float>();
        // max(y, -1)
        AscendC::Maximum(t, yLocal, -1.0f, n);
        // min(t, 1)
        AscendC::Minimum(yLocal, t, 1.0f, n);
        tmpQueue1_.FreeTensor(clampMax);
        tmpQueue2_.FreeTensor(clampMin);
        tmpQueue3_.FreeTensor(t);

        // Step 3: Mish = x * tanh(softplus(x))
        AscendC::LocalTensor<float> softplus = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> onePlusExp = tmpQueue2_.AllocTensor<float>();
        AscendC::Exp(softplus, yLocal, n);               // exp(x)
        AscendC::Adds(onePlusExp, softplus, 1.0f, n);   // 1+exp(x)
        AscendC::Log(softplus, onePlusExp, n);           // log(1+exp(x))
        AscendC::LocalTensor<float> tanhSoftplus = tmpQueue3_.AllocTensor<float>();
        AscendC::Tanh(tanhSoftplus, softplus, n);
        AscendC::Mul(yLocal, yLocal, tanhSoftplus, n);
        tmpQueue1_.FreeTensor(softplus);
        tmpQueue2_.FreeTensor(onePlusExp);
        tmpQueue3_.FreeTensor(tanhSoftplus);

        // Step 4: Group Normalization
        uint32_t groups = numGroups_;
        uint32_t channelsPerGroup = n / groups;
        // Temporary scalars as 1-element tensors to avoid float/uint casts
        AscendC::LocalTensor<float> sumScalar = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> sqSumScalar = tmpQueue2_.AllocTensor<float>();
        AscendC::LocalTensor<float> countFloat = tmpQueue3_.AllocTensor<float>();
        AscendC::LocalTensor<uint32_t> countInt = tmpQueue4_.AllocTensor<uint32_t>();
        // Set countInt to channelsPerGroup
        countInt.SetValue(0, channelsPerGroup);
        // Cast to float (allowed via tensor cast)
        AscendC::Cast(countFloat, countInt, 1);
        AscendC::LocalTensor<float> meanScalar = tmpQueue5_.AllocTensor<float>();
        AscendC::LocalTensor<float> varScalar = tmpQueue6_.AllocTensor<float>();

        for (uint32_t g = 0; g < groups; g++) {
            uint32_t start = g * channelsPerGroup;
            // Extract group slice into a temporary local tensor? We'll use slice views.
            // AscendC does not support slicing, so we use loops.
            // Compute sum
            float tempSum = 0.0f;
            for (uint32_t c = 0; c < channelsPerGroup; c++) {
                tempSum += yLocal.GetValue(start + c);
            }
            sumScalar.SetValue(0, tempSum);
            // mean = sum / channelsPerGroup (vector div of 1-element tensors)
            AscendC::Div(meanScalar, sumScalar, countFloat, 1);
            // Compute variance
            float tempSqSum = 0.0f;
            float mean = meanScalar.GetValue(0);
            for (uint32_t c = 0; c < channelsPerGroup; c++) {
                float diff = yLocal.GetValue(start + c) - mean;
                tempSqSum += diff * diff;
            }
            sqSumScalar.SetValue(0, tempSqSum);
            AscendC::Div(varScalar, sqSumScalar, countFloat, 1);
            // var + eps
            AscendC::LocalTensor<float> varPlusEps = tmpQueue4_.AllocTensor<float>();
            AscendC::Adds(varPlusEps, varScalar, eps_, 1);
            // sqrt(var+eps) -> 1-element tensor
            AscendC::LocalTensor<float> std = tmpQueue5_.AllocTensor<float>();
            AscendC::Sqrt(std, varPlusEps, 1);
            // invStd = 1.0 / std
            AscendC::LocalTensor<float> invStd = tmpQueue6_.AllocTensor<float>();
            AscendC::Reciprocal(invStd, std, 1);
            float invStdVal = invStd.GetValue(0);

            // Normalize group elements
            for (uint32_t c = 0; c < channelsPerGroup; c++) {
                float val = (yLocal.GetValue(start + c) - mean) * invStdVal;
                val = val * gnGammaGm_.GetValue(start + c) + gnBetaGm_.GetValue(start + c);
                yLocal.SetValue(start + c, val);
            }
            tmpQueue4_.FreeTensor(varPlusEps);
            tmpQueue5_.FreeTensor(std);
            tmpQueue6_.FreeTensor(invStd);
        }

        tmpQueue1_.FreeTensor(sumScalar);
        tmpQueue2_.FreeTensor(sqSumScalar);
        tmpQueue3_.FreeTensor(countFloat);
        tmpQueue4_.FreeTensor(countInt);
        tmpQueue5_.FreeTensor(meanScalar);
        tmpQueue6_.FreeTensor(varScalar);

        // Copy output to global memory
        AscendC::DataCopy(yGm_[sampleIdx * outFeatures_], yLocal, n);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue1_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue2_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue3_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue4_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue5_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue6_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> linBiasGm_;
    AscendC::GlobalTensor<float> biasGm_;
    AscendC::GlobalTensor<float> gnGammaGm_;
    AscendC::GlobalTensor<float> gnBetaGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t batchSize_ {0};
    uint32_t inFeatures_ {0};
    uint32_t outFeatures_ {0};
    uint32_t numGroups_ {1};
    float eps_ {1e-5f};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void gemm_bias_add_hardtanh_mish_group_norm_custom(GM_ADDR x, GM_ADDR weight, GM_ADDR lin_bias,
                                                                  GM_ADDR bias, GM_ADDR gn_gamma, GM_ADDR gn_beta,
                                                                  GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelGemmBiasAddHardtanhMishGroupNormCustom op;
    op.Init(x, weight, lin_bias, bias, gn_gamma, gn_beta, y,
            tiling_data.batchSize, tiling_data.inFeatures,
            tiling_data.outFeatures, tiling_data.numGroups,
            tiling_data.eps, tiling_data.tileLen);
    op.Process();
}
